defmodule Storybook.TaskComponents.TaskInput do
  use PhoenixStorybook.Story, :component

  def function, do: &TodoListWeb.TaskComponents.task_input/1
  def render_source, do: :function

  def variations do
    [
      %Variation{
        id: :default,
        description: "Default with placeholder"
      },
      %Variation{
        id: :custom_placeholder,
        description: "Custom placeholder",
        attributes: %{placeholder: "Add a new task..."}
      }
    ]
  end
end

defmodule Storybook.TaskComponents.InlineEditField do
  use PhoenixStorybook.Story, :component

  def function, do: &TodoListWeb.TaskComponents.inline_edit_field/1
  def render_source, do: :function

  def variations do
    [
      %Variation{
        id: :with_text,
        description: "Editing existing description",
        attributes: %{task_id: "task-001", description: "Call the dentist office"}
      },
      %Variation{
        id: :short_text,
        description: "Short description being edited",
        attributes: %{task_id: "task-002", description: "Buy milk"}
      }
    ]
  end
end
